module jk_flip_flop (  
    input obf_J,  
    input K,  
    input clk,  
    output reg Q  
);  
    always @(posedge clk) begin  
        if (obf_J && !K)  
            Q <= 1; // Set  
        else if (!obf_J && K)  
            Q <= 0; // Reset  
        else if (obf_J && K)  
            Q <= ~Q; // Toggle  
        // If obf_J = 0 and K = 0, Q remains the same  
    end  
endmodule
